const body = $input.first().json.body;
const command = (body.command || '/ai').toLowerCase();
const rawText = (body.text || '').trim();
const userId = body.user_id || '';
const userName = body.user_name || 'unknown';
const channelId = body.channel_id || '';
const responseUrl = body.response_url || '';

// ── Slash command routing ─────────────────────────────────────────────
// /image <prompt>    → ComfyUI text-to-image → #studio-canvas
// /video <prompt>    → ComfyUI text-to-video → #studio-reels
// /enhance <url>     → ComfyUI image enhance
// /news [topic]      → News article search
// /3d <description>  → OpenSCAD 3D model generation
// /patent <idea>     → AI patent specification writer
// /ai [agent:] text  → Council member or direct Ollama
// /summarize <url>   → Summarize a URL
// /review <code>     → Jason code review

if (command === '/image' || rawText.toLowerCase().startsWith('image:')) {
  const prompt = command === '/image' ? rawText : rawText.replace(/^image:/i,'').trim();
  return [{ json: {
    route: 'studio_image',
    prompt,
    channelId: 'C0AKW7W9ZPX', // #studio-canvas
    sourceChannel: channelId,
    userId, userName, responseUrl
  }}];
}

if (command === '/video' || rawText.toLowerCase().startsWith('video:')) {
  const prompt = command === '/video' ? rawText : rawText.replace(/^video:/i,'').trim();
  return [{ json: {
    route: 'studio_video',
    prompt,
    channelId: 'C0AKJ788GJK', // #studio-reels
    sourceChannel: channelId,
    userId, userName, responseUrl
  }}];
}

if (command === '/enhance' || rawText.toLowerCase().startsWith('enhance:')) {
  const imageUrl = command === '/enhance' ? rawText : rawText.replace(/^enhance:/i,'').trim();
  return [{ json: {
    route: 'studio_enhance',
    imageUrl,
    channelId,
    userId, userName, responseUrl
  }}];
}

if (command === '/news' || rawText.toLowerCase().startsWith('news:')) {
  const query = command === '/news'
    ? (rawText || 'AI agents automation')
    : rawText.replace(/^news:/i,'').trim();
  return [{ json: {
    route: 'news',
    query,
    channelId,
    userId, userName, responseUrl
  }}];
}

if (command === '/3d' || rawText.toLowerCase().startsWith('3d:')) {
  const description = command === '/3d' ? rawText : rawText.replace(/^3d:/i,'').trim();
  if (!description) {
    return [{ json: { route: 'help', channelId, userId, userName, responseUrl }}];
  }
  return [{ json: {
    route: 'cad_3d',
    description,
    channelId,
    userId, userName, responseUrl
  }}];
}

if (command === '/patent' || rawText.toLowerCase().startsWith('patent:')) {
  const description = command === '/patent' ? rawText : rawText.replace(/^patent:/i,'').trim();
  if (!description) {
    return [{ json: { route: 'help', channelId, userId, userName, responseUrl }}];
  }
  return [{ json: {
    route: 'patent',
    description,
    channelId,
    userId, userName, responseUrl
  }}];
}


if (command === '/summarize') {
  const url = rawText.trim();
  if (!url || !url.startsWith('http')) {
    return [{ json: { route: 'help', channelId, userId, userName, responseUrl }}];
  }
  return [{ json: {
    route: 'summarize',
    url,
    channelId, userId, userName, responseUrl
  }}];
}

if (command === '/review') {
  const code = rawText.trim();
  if (!code) {
    return [{ json: { route: 'help', channelId, userId, userName, responseUrl }}];
  }
  return [{ json: {
    route: 'review',
    code,
    channelId, userId, userName, responseUrl
  }}];
}

if (command === '/pm' || rawText.toLowerCase().startsWith('pm:')) {
  const message = command === '/pm' ? rawText : rawText.replace(/^pm:/i,'').trim();
  if (!message) {
    return [{ json: { route: 'help', channelId, userId, userName, responseUrl }}];
  }
  return [{ json: {
    route: 'pm',
    text: message,
    channelId, userId, userName, responseUrl
  }}];
}

// Default: /ai with optional agent prefix (kevin:, jason:, etc.)
const AGENTS = ['kevin','jason','scaachi','christian','chidi'];
const MODEL_MAP = {
  kevin: 'kevin:latest', jason: 'jason:latest', scaachi: 'scaachi:latest',
  christian: 'christian:latest', chidi: 'chidi:latest'
};

let agent = 'kevin';
let userText = rawText;

for (const a of AGENTS) {
  if (rawText.toLowerCase().startsWith(a + ':')) {
    agent = a;
    userText = rawText.slice(a.length + 1).trim();
    break;
  }
}

if (!userText) {
  return [{ json: { route: 'help', channelId, userId, userName, responseUrl }}];
}

return [{ json: {
  route: 'ai',
  agent,
  model: MODEL_MAP[agent],
  userText,
  channelId, userId, userName, responseUrl
}}];

const ollamaResp = $input.first().json;
const parsed = $('Parse Command').first().json;

const content = ollamaResp.message?.content || 'No response from model.';
const MAX = 2800;
const truncated = content.length > MAX
  ? content.slice(0, MAX) + '\n_[response truncated]_'
  : content;

return [{ json: {
  responseUrl: parsed.responseUrl,
  agent: parsed.agent,
  userId: parsed.userId,
  slackPayload: JSON.stringify({
    response_type: 'in_channel',
    blocks: [
      {
        type: 'context',
        elements: [{ type: 'mrkdwn', text: ':robot_face: *' + parsed.agent + '* responding to <@' + parsed.userId + '>' }]
      },
      {
        type: 'section',
        text: { type: 'mrkdwn', text: truncated }
      }
    ]
  })
}}];

