const parsed = $('Parse Command').first().json;
const html = $input.first().json.data || $input.first().json.body || '';
// Strip HTML tags, collapse whitespace, truncate
const text = html
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&nbsp;/g, ' ')
  .replace(/\s{2,}/g, ' ')
  .trim()
  .slice(0, 3500);

return [{ json: {
  pageText: text,
  url: parsed.url,
  responseUrl: parsed.responseUrl,
  userId: parsed.userId
}}];

