={{ JSON.stringify({
  model: "scaachi:latest",
  stream: false,
  format: "json",
  options: { temperature: 0 },
  messages: [
    {
      role: "system",
      content: "You are Scaachi, a sharp and curious AI assistant. Summarize the provided web page content concisely. Return JSON: { \"summary\": \"2-3 paragraph summary\", \"key_points\": [\"point1\", \"point2\", \"point3\"] }"
    },
    {
      role: "user",
      content: "Summarize this web page content:\n\n" + $json.pageText
    }
  ]
}) }}

={{ (() => {
  const resp = $input.first().json;
  const url = $('Strip HTML').first().json.url;
  const userId = $('Strip HTML').first().json.userId;
  let parsed;
  try { parsed = JSON.parse(resp.message?.content || '{}'); } catch(e) { parsed = {}; }
  const summary = parsed.summary || resp.message?.content || 'Could not summarize.';
  const points = (parsed.key_points || []).map(p => '• ' + p).join('\n');
  const MAX = 2500;
  const text = summary.length > MAX ? summary.slice(0, MAX) + '...' : summary;
  return JSON.stringify({
    response_type: 'in_channel',
    blocks: [
      { type: 'context', elements: [{ type: 'mrkdwn', text: ':mag: *Scaachi* summarized <' + url + '|this page> for <@' + userId + '>' }] },
      { type: 'section', text: { type: 'mrkdwn', text: text } },
      ...(points ? [{ type: 'section', text: { type: 'mrkdwn', text: '*Key Points:*\n' + points } }] : [])
    ]
  });
})() }}

={{ JSON.stringify({
  model: "jason:latest",
  stream: false,
  format: "json",
  options: { temperature: 0 },
