    },
    {
      role: "user",
      content: "Review this code:\n\n" + $('Parse Command').first().json.code
    }
  ]
}) }}

={{ (() => {
  const resp = $input.first().json;
  const userId = $('Parse Command').first().json.userId;
  let parsed;
  try { parsed = JSON.parse(resp.message?.content || '{}'); } catch(e) { parsed = {}; }
  const verdict = parsed.verdict || 'REVIEWED';
  const summary = parsed.summary || 'Review complete.';
  const issues = (parsed.issues || []).slice(0, 5).map(i =>
    `${i.severity === 'high' ? ':red_circle:' : i.severity === 'medium' ? ':large_yellow_circle:' : ':white_circle:'} ${i.line || i.description || 'Issue'} → ${i.fix || ''}`
  ).join('\n');
  const strengths = (parsed.strengths || []).map(s => '• ' + s).join('\n');
  const verdictEmoji = verdict === 'LGTM' ? ':white_check_mark:' : verdict === 'CRITICAL' ? ':x:' : ':warning:';
  return JSON.stringify({
    response_type: 'in_channel',
    blocks: [
      { type: 'context', elements: [{ type: 'mrkdwn', text: ':pencil: *Jason* reviewed code for <@' + userId + '> — ' + verdictEmoji + ' ' + verdict }] },
      { type: 'section', text: { type: 'mrkdwn', text: summary } },
      ...(issues ? [{ type: 'section', text: { type: 'mrkdwn', text: '*Issues:*\n' + issues } }] : []),
      ...(strengths ? [{ type: 'section', text: { type: 'mrkdwn', text: '*Strengths:*\n' + strengths } }] : [])
    ]
  });
})() }}
